// =============================================
// SECOND BRAIN DASHBOARD — Main Entry Point
// =============================================
// Vite ES module entry. Sets up Three.js, lucide, then loads the app.

import * as THREE from 'three';
import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
import { RenderPass } from 'three/addons/postprocessing/RenderPass.js';
import { ShaderPass } from 'three/addons/postprocessing/ShaderPass.js';
import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js';
import { OutputPass } from 'three/addons/postprocessing/OutputPass.js';
import { createIcons, icons } from 'lucide';

// Assign post-processing classes to the THREE namespace
// (The bundle code expects THREE.EffectComposer, THREE.RenderPass, etc.)
const THREE_PLUS = Object.assign({}, THREE, {
  EffectComposer,
  RenderPass,
  ShaderPass,
  UnrealBloomPass,
  OutputPass,
});

// Make THREE available globally with post-processing attached
window.THREE = THREE_PLUS;

// Make lucide available globally
window.lucide = { createIcons, icons };

// Now load the app bundle
import './app.js';
